import React, { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import {
  getMyAccidentHistory,
  getMyNotifications,
  getMyResponses,
  markNotificationRead,
  submitSafetyResponse,
} from "../../service/apiservice";
import { connectSocket, disconnectSocket } from "../../service/socketService";
import { clearAuth, getStoredUser } from "../../utils/auth";
import "./UserDash.css";

const CitizenDashboard = () => {
  const user = useMemo(() => getStoredUser(), []);
  const navigate = useNavigate();

  const [notifications, setNotifications] = useState([]);
  const [history, setHistory] = useState([]);
  const [responses, setResponses] = useState([]);
  const [activePrompt, setActivePrompt] = useState(null);
  const [error, setError] = useState("");

  const loadData = async () => {
    try {
      const [notiRes, historyRes, responseRes] = await Promise.all([
        getMyNotifications(),
        getMyAccidentHistory(),
        getMyResponses(),
      ]);
      setNotifications(notiRes.notifications || []);
      setHistory(historyRes.history || []);
      setResponses(responseRes.responses || []);
    } catch (err) {
      setError(err.message || "Failed to load dashboard data");
    }
  };

  useEffect(() => {
    loadData();

    const socket = connectSocket();

    socket.on("alert:accident", (payload) => {
      setNotifications((prev) => [
        {
          _id: `live-${Date.now()}`,
          type: "ACCIDENT_ALERT",
          message: `Accident ${payload.severity} detected. Please confirm safety.`,
          isRead: false,
          createdAt: new Date().toISOString(),
        },
        ...prev,
      ]);
    });

    socket.on("chatbot:trigger", (payload) => {
      setActivePrompt({ accidentId: payload.accidentId, startedAt: Date.now() });
    });

    socket.on("chatbot:timeout", (payload) => {
      setActivePrompt(null);
      setNotifications((prev) => [
        {
          _id: `timeout-${Date.now()}`,
          type: "SYSTEM",
          message: payload.message,
          isRead: false,
          createdAt: new Date().toISOString(),
        },
        ...prev,
      ]);
      loadData();
    });

    return () => {
      socket.off("alert:accident");
      socket.off("chatbot:trigger");
      socket.off("chatbot:timeout");
      disconnectSocket();
    };
  }, []);

  const onSafetyResponse = async (responseType) => {
    if (!activePrompt) return;

    try {
      await submitSafetyResponse({
        accidentId: activePrompt.accidentId,
        responseType,
        responseTimeMs: Date.now() - activePrompt.startedAt,
      });
      setActivePrompt(null);
      await loadData();
    } catch (err) {
      setError(err.message || "Failed to submit response");
    }
  };

  const onMarkRead = async (notificationId) => {
    try {
      await markNotificationRead(notificationId);
      setNotifications((prev) => prev.map((n) => (n._id === notificationId ? { ...n, isRead: true } : n)));
    } catch (err) {
      setError(err.message || "Failed to mark notification");
    }
  };

  const logout = () => {
    clearAuth();
    navigate("/login");
  };

  return (
    <div className="user-page">
      <header className="user-header">
        <div>
          <h2>Citizen Dashboard</h2>
          <p>{user?.name} ({user?.email})</p>
        </div>
        <button onClick={logout}>Logout</button>
      </header>

      {error && <p className="error-text">{error}</p>}

      <section className="grid-two">
        <article className="card">
          <h3>In-App Notifications</h3>
          <ul className="list">
            {notifications.map((n) => (
              <li key={n._id}>
                <div>
                  <strong>{n.type}</strong>
                  <p>{n.message}</p>
                </div>
                {!String(n._id).startsWith("live-") && !String(n._id).startsWith("timeout-") && !n.isRead && (
                  <button onClick={() => onMarkRead(n._id)}>Mark read</button>
                )}
              </li>
            ))}
          </ul>
        </article>

        <article className="card">
          <h3>My Responses</h3>
          <ul className="list simple">
            {responses.map((r) => (
              <li key={r._id}>
                <span>{r.responseType}</span>
                <small>{new Date(r.createdAt).toLocaleString()}</small>
              </li>
            ))}
          </ul>
        </article>
      </section>

      <section className="card">
        <h3>Interaction History</h3>
        <table>
          <thead>
            <tr>
              <th>Time</th>
              <th>Severity</th>
              <th>Status</th>
              <th>Your Response</th>
            </tr>
          </thead>
          <tbody>
            {history.map((h) => (
              <tr key={h.responseId}>
                <td>{new Date(h.createdAt).toLocaleString()}</td>
                <td>{h.accident?.severity}</td>
                <td>{h.accident?.status}</td>
                <td>{h.responseType}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </section>

      {activePrompt && (
        <div className="chatbot-modal">
          <div className="chatbot-card">
            <h3>Safety Confirmation</h3>
            <p>Accident detected nearby. Are you safe?</p>
            <div className="actions">
              <button onClick={() => onSafetyResponse("Safe")}>I'm Safe</button>
              <button className="danger" onClick={() => onSafetyResponse("Help")}>Need Help</button>
              <button onClick={() => setActivePrompt(null)}>Ignore</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CitizenDashboard;
